"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[3552],{19164(n,e,i){i.r(e),i.d(e,{assets:()=>d,contentTitle:()=>o,default:()=>A,frontMatter:()=>a,metadata:()=>r,toc:()=>l});const r=JSON.parse('{"id":"Examples/General/MdispWindowQt/CPP","title":"MdispWindowQt","description":"This program displays a welcoming message in a user-defined window and grabs (if supported) in it. It uses the AIL system and the MdispSelectWindow() function to display the AIL buffer in a user-created client window.","source":"@site/docs/Examples/General/MdispWindowQt/CPP.md","sourceDirName":"Examples/General/MdispWindowQt","slug":"/Examples/General/MdispWindowQt/CPP","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Examples/General/MdispWindowQt/CPP","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"title":"MdispWindowQt","description":"This program displays a welcoming message in a user-defined window and grabs (if supported) in it. It uses the AIL system and the MdispSelectWindow() function to display the AIL buffer in a user-created client window.","ms.language":"C++"},"sidebar":"examplesSidebar","previous":{"title":"MdispWindowLeveling","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Examples/General/MdispWindowLeveling/Python_Object"},"next":{"title":"MdispWindowQt","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Examples/General/MdispWindowQt/CPP_Object"}}');var t=i(74848),s=i(28453);const a={title:"MdispWindowQt",description:"This program displays a welcoming message in a user-defined window and grabs (if supported) in it. It uses the AIL system and the MdispSelectWindow() function to display the AIL buffer in a user-created client window.","ms.language":"C++"},o="MdispWindowQt",d={},l=[];function c(n){const e={blockquote:"blockquote",code:"code",h1:"h1",header:"header",p:"p",pre:"pre",strong:"strong",...(0,s.R)(),...n.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsx)(e.header,{children:(0,t.jsx)(e.h1,{id:"mdispwindowqt",children:"MdispWindowQt"})}),"\n",(0,t.jsxs)(e.blockquote,{children:["\n",(0,t.jsx)(e.p,{children:"This program displays a welcoming message in a user-defined window and grabs (if supported) in it. It uses the AIL system and the MdispSelectWindow() function to display the AIL buffer in a user-created client window."}),"\n"]}),"\n",(0,t.jsxs)(e.p,{children:[(0,t.jsx)(e.strong,{children:"Language:"})," C++"]}),"\n",(0,t.jsxs)(e.p,{children:[(0,t.jsx)(e.strong,{children:"Functions used:"})," ",(0,t.jsx)(e.code,{children:"MdispFree"}),", ",(0,t.jsx)(e.code,{children:"MappAlloc"}),", ",(0,t.jsx)(e.code,{children:"MappFree"}),", ",(0,t.jsx)(e.code,{children:"MbufAllocColor"}),", ",(0,t.jsx)(e.code,{children:"MbufClear"}),", ",(0,t.jsx)(e.code,{children:"MbufFree"}),", ",(0,t.jsx)(e.code,{children:"MdigAlloc"}),", ",(0,t.jsx)(e.code,{children:"MdigFree"}),", ",(0,t.jsx)(e.code,{children:"MdigGrabContinuous"}),", ",(0,t.jsx)(e.code,{children:"MdigHalt"}),", ",(0,t.jsx)(e.code,{children:"MdigInquire"}),", ",(0,t.jsx)(e.code,{children:"MdispAlloc"}),", ",(0,t.jsx)(e.code,{children:"MdispSelect"}),", ",(0,t.jsx)(e.code,{children:"MdispSelectWindow"}),", ",(0,t.jsx)(e.code,{children:"MgraFont"}),", ",(0,t.jsx)(e.code,{children:"MgraRect"}),", ",(0,t.jsx)(e.code,{children:"MgraText"}),", ",(0,t.jsx)(e.code,{children:"MsysAlloc"}),", ",(0,t.jsx)(e.code,{children:"MsysFree"}),", ",(0,t.jsx)(e.code,{children:"MsysInquire"})]}),"\n",(0,t.jsxs)(e.p,{children:[(0,t.jsx)(e.strong,{children:"Categories:"})," Overview, General, Industries, Applications, Modules, Buffer, Display, Graphics, Digitizer, What's New, Older"]}),"\n",(0,t.jsx)(e.pre,{children:(0,t.jsx)(e.code,{className:"language-cpp",children:'///////////////////////////////////////////////////////////////////////////////\r\n// Aurora Imaging Library\r\n// Filename:    MDispWindowQt.cpp\r\n//\r\n// Description: This program displays a welcoming message in a user-defined\r\n//              window and grabs (if supported) in it. It uses\r\n//              the system and the MdispSelectWindow() function\r\n//              to display the buffer in a user-created client window.\r\n//         \r\n//              This version uses the Qt library to create the client window.\r\n//\r\n// (C) 1992-2026 Zebra Technologies Corp. and/or its affiliates\r\n// All Rights Reserved\r\n///////////////////////////////////////////////////////////////////////////////\r\n\r\n#include "MdispWindowQt.h"\r\n#ifdef _MSC_VER\r\n#pragma warning(disable:4127)\r\n#endif\r\n#include <QApplication>\r\n#include <QAction>\r\n#include <QMainWindow>\r\n#include <QMessageBox>\r\n#include <QToolBar>\r\n#ifdef _MSC_VER\r\n#pragma warning(default:4127)\r\n#endif\r\n\r\n#include <AIL.h>\r\n\r\n\r\n#if STATIC_QT\r\n#include <QtPlugin>\r\n#if !M_AIL_USE_LINUX\r\nQ_IMPORT_PLUGIN(QWindowsIntegrationPlugin)\r\n#else\r\nQ_IMPORT_PLUGIN(QXcbIntegrationPlugin)\r\n#endif\r\n#endif\r\n\r\n#if M_AIL_USE_LINUX\r\n#include <X11/Xlib.h>\r\n#if QT_VERSION >= QT_VERSION_CHECK(5, 0, 0)\r\nvoid MessageOutput(QtMsgType type, const QMessageLogContext &context, const QString &msg)\r\n   {\r\n   QByteArray localMsg = msg.toLocal8Bit();\r\n   switch (type)\r\n      {\r\n      case QtDebugMsg:\r\n         fprintf(stderr, "Debug: %s (%s:%u, %s)\\n", localMsg.constData(), context.file, context.line, context.function);\r\n         break;\r\n      case QtWarningMsg:\r\n#if QT_VERSION >= QT_VERSION_CHECK(5, 5, 0)         \r\n      case QtInfoMsg:\r\n#endif\r\n         break;\r\n      case QtCriticalMsg:\r\n         fprintf(stderr, "Critical: %s (%s:%u, %s)\\n", localMsg.constData(), context.file, context.line, context.function);\r\n         break;\r\n      case QtFatalMsg:\r\n         fprintf(stderr, "Fatal: %s (%s:%u, %s)\\n", localMsg.constData(), context.file, context.line, context.function);\r\n         abort();\r\n      }\r\n   }\r\n#endif\r\n#endif\r\n\r\n\r\n// Window title. \r\n#define AIL_APPLICATION_NAME      "Aurora Imaging Library application"\r\n\r\n// Default image dimensions. \r\n#define DEFAULT_IMAGE_SIZE_X       640\r\n#define DEFAULT_IMAGE_SIZE_Y       480\r\n#define DEFAULT_IMAGE_SIZE_BAND      1\r\n\r\n\r\n//****************************************************************\r\n//\r\n// Name:         AilApplication()\r\n//\r\n// synopsis:     This function is the core of the application that\r\n//               is executed when this program is started. See main()\r\n//               below for the program entry point.\r\n//\r\n//               It uses Aurora Imaging Library to display a welcoming message in the\r\n//               specified user window and to grab in it if it is\r\n//               supported by the target system.\r\n//\r\n//***************************************************************\r\nvoid AilApplication(PaintArea *Area)\r\n   {\r\n   // Variables \r\n   AIL_ID AilApplication, // Application identifier.\r\n      AilDisplay,\r\n      AilSystem,      // System identifier.       \r\n      AilDigitizer,   // Digitizer identifier.    \r\n      AilImage;       // Image buffer identifier. \r\n\r\n   AIL_INT BufSizeX    = 0;\r\n   AIL_INT BufSizeY    = 0;\r\n   AIL_INT BufSizeBand = 0;\r\n\r\n   // Allocate an application. \r\n   MappAlloc(M_NULL, M_DEFAULT, &AilApplication);\r\n\r\n   // Allocate a system. \r\n   MsysAlloc(M_DEFAULT, AIL_TEXT("M_DEFAULT"), M_DEFAULT, M_DEFAULT, &AilSystem);\r\n\r\n   // Allocate a display. \r\n   MdispAlloc(AilSystem, M_DEFAULT, AIL_TEXT("M_DEFAULT"), M_WINDOWED, &AilDisplay);\r\n\r\n   // Allocate a digitizer if supported and sets the target image size. \r\n   if (MsysInquire(AilSystem, M_DIGITIZER_NUM, M_NULL) > 0)\r\n      {\r\n      MdigAlloc(AilSystem, M_DEFAULT, AIL_TEXT("M_DEFAULT"), M_DEFAULT, &AilDigitizer);\r\n      MdigInquire(AilDigitizer, M_SIZE_X,    &BufSizeX);\r\n      MdigInquire(AilDigitizer, M_SIZE_Y,    &BufSizeY);\r\n      MdigInquire(AilDigitizer, M_SIZE_BAND, &BufSizeBand);\r\n      // Resize the display window \r\n      if((BufSizeX > DEFAULT_IMAGE_SIZE_X) || (BufSizeY > DEFAULT_IMAGE_SIZE_Y))\r\n         {\r\n         if(Area->parentWidget())\r\n            {\r\n            AilWindow* MainWindow = (AilWindow*)Area->parentWidget();\r\n            MainWindow->resize(BufSizeX, BufSizeY+ MainWindow->ToolBar()->height());\r\n            }\r\n         }\r\n      }\r\n   else\r\n      {\r\n      AilDigitizer = M_NULL;\r\n      BufSizeX     = DEFAULT_IMAGE_SIZE_X;\r\n      BufSizeY     = DEFAULT_IMAGE_SIZE_Y;\r\n      BufSizeBand  = DEFAULT_IMAGE_SIZE_BAND;\r\n      }\r\n\r\n   // Allocate a buffer. \r\n   MbufAllocColor(AilSystem, BufSizeBand, BufSizeX, BufSizeY, 8+M_UNSIGNED,\r\n                  (AilDigitizer ? M_IMAGE+M_DISP+M_GRAB : M_IMAGE+M_DISP), &AilImage);\r\n\r\n   // Clear the buffer \r\n   MbufClear(AilImage,0);\r\n\r\n   // Select the buffer to be displayed in the user-specified window \r\n   MdispSelectWindow(AilDisplay, AilImage, (AIL_WINDOW_HANDLE)Area->UserWindowHandle());\r\n\r\n   // Print a string in the image buffer using AIL.\r\n   // Note: When a buffer is modified using a command, the display\r\n   // automatically updates the window passed to MdispSelectWindow().\r\n   MgraFont(M_DEFAULT, M_FONT_DEFAULT_MEDIUM);\r\n   MgraText(M_DEFAULT, AilImage, (BufSizeX/8)*2 + 20, BufSizeY/2,\r\n            AIL_TEXT("Aurora Imaging Library"));\r\n   MgraRect(M_DEFAULT, AilImage, ((BufSizeX/8)*2)-60, (BufSizeY/2)-80,\r\n            ((BufSizeX/8)*2)+370, (BufSizeY/2)+100);\r\n   MgraRect(M_DEFAULT, AilImage, ((BufSizeX/8)*2)-40, (BufSizeY/2)-60,\r\n            ((BufSizeX/8)*2)+350, (BufSizeY/2)+80);\r\n   MgraRect(M_DEFAULT, AilImage, ((BufSizeX/8)*2)-20, (BufSizeY/2)-40,\r\n            ((BufSizeX/8)*2)+330, (BufSizeY/2)+60);\r\n\r\n   // Open a message box to wait for a key. \r\n   QMessageBox::information(0, "application example",\r\n                            "\\"Aurora Imaging Library\\" was printed", QMessageBox::Ok);\r\n\r\n   // Grab in the user window if supported. \r\n   if (AilDigitizer)\r\n      {\r\n      // Grab continuously. \r\n      MdigGrabContinuous(AilDigitizer, AilImage);\r\n\r\n      // Open a message box to wait for a key. \r\n      QMessageBox::information(0, "application example",\r\n                               "Continuous grab in progress", QMessageBox::Ok);\r\n\r\n      // Stop continuous grab. \r\n      MdigHalt(AilDigitizer);\r\n      }\r\n   Area->setAttribute(Qt::WA_OpaquePaintEvent, false);\r\n   Area->setAttribute(Qt::WA_PaintOnScreen, false);\r\n\r\n   // Remove the buffer from the display. \r\n   MdispSelect(AilDisplay, M_NULL);\r\n\r\n   // Free allocated objects. \r\n   MbufFree(AilImage);\r\n\r\n\r\n   if (AilDigitizer)\r\n      MdigFree(AilDigitizer);\r\n   MdispFree(AilDisplay);\r\n   MsysFree(AilSystem);\r\n   MappFree(AilApplication);\r\n   }\r\n\r\n\r\nPaintArea::PaintArea(QWidget* parent)\r\n   : QWidget(parent)\r\n   , m_UserWindowHandle(0)\r\n   {\r\n   }\r\n\r\nvoid PaintArea::startAil()\r\n   {\r\n   setAttribute(Qt::WA_OpaquePaintEvent);\r\n   setAttribute(Qt::WA_PaintOnScreen);\r\n   setAttribute(Qt::WA_NoSystemBackground);\r\n   m_UserWindowHandle = winId();\r\n   AilApplication(this);\r\n   repaint();\r\n   }\r\n\r\nbool PaintArea::event(QEvent* e )\r\n   {\r\n\r\n#if QT_VERSION >= 0x040602 && M_AIL_USE_LINUX\r\n   if(e->type() == QEvent::WinIdChange || e->type() == QEvent::Show)\r\n#else\r\n      if(e->type() == QEvent::Show)\r\n#endif\r\n         m_UserWindowHandle = winId();\r\n   return QWidget::event(e);\r\n   }\r\n\r\nQSize PaintArea::sizeHint() const\r\n   {\r\n   return QSize(DEFAULT_IMAGE_SIZE_X, DEFAULT_IMAGE_SIZE_Y);\r\n   }\r\n\r\nAilWindow::AilWindow()\r\n   : QMainWindow(),\r\n     m_PaintArea(0)\r\n   {\r\n\r\n   setWindowTitle(AIL_APPLICATION_NAME);\r\n\r\n   QAction *startAct = new QAction(tr("&Start"), this);\r\n   startAct->setShortcut(tr("Ctrl+s"));\r\n   connect(startAct, &QAction::triggered, this, &AilWindow::start);\r\n\r\n   m_Tools = new QToolBar(tr("Tool Bar"), this);\r\n   m_Tools->setMovable(false);\r\n   m_Tools->addAction(startAct);\r\n   addToolBar(m_Tools);\r\n\r\n   m_PaintArea = new PaintArea(this);\r\n   m_PaintArea->resize(DEFAULT_IMAGE_SIZE_X, DEFAULT_IMAGE_SIZE_Y);\r\n   setCentralWidget(m_PaintArea);\r\n\r\n   }\r\n\r\nvoid AilWindow::start()\r\n   {\r\n   m_PaintArea->startAil();\r\n   }\r\n\r\n\r\n//****************************************************************\r\n//\r\n//   Name:     main()\r\n//\r\n//   Synopsis: Call initialization function, processes message loop.\r\n//\r\n//***************************************************************\r\nint main(int argc, char* argv[])\r\n   {\r\n#if M_AIL_USE_LINUX\r\n   qputenv("QT_QPA_PLATFORM", "xcb");\r\n   XInitThreads();\r\n#if QT_VERSION >= QT_VERSION_CHECK(5, 0, 0)   \r\n   qInstallMessageHandler(MessageOutput);\r\n#endif\r\n#endif\r\n   QApplication a(argc, argv);\r\n   AilWindow *w = new AilWindow;\r\n   w->show();\r\n   return a.exec();\r\n   }\r\n\r\n#if  QT_VERSION < QT_VERSION_CHECK(6, 0, 0)\r\n#if (M_AIL_USE_LINUX && !STATIC_QT) || (M_AIL_USE_WINDOWS)\r\n#include "moc_MdispWindowQt.cpp"\r\n#endif\r\n#else\r\n#if M_AIL_USE_WINDOWS || !STATIC_QT\r\n#include "moc_MdispWindowQt.cpp"\r\n#endif\r\n#endif\r\n\n'})})]})}function A(n={}){const{wrapper:e}={...(0,s.R)(),...n.components};return e?(0,t.jsx)(e,{...n,children:(0,t.jsx)(c,{...n})}):c(n)}},28453(n,e,i){i.d(e,{R:()=>a,x:()=>o});var r=i(96540);const t={},s=r.createContext(t);function a(n){const e=r.useContext(s);return r.useMemo(function(){return"function"==typeof n?n(e):{...e,...n}},[e,n])}function o(n){let e;return e=n.disableParentContext?"function"==typeof n.components?n.components(t):n.components||t:a(n.components),r.createElement(s.Provider,{value:e},n.children)}}}]);